		function api(rID, rType, rConfirm=false) {
            if ((window.rSelected) && (window.rSelected.length > 0)) {
                $.toast("Individual actions disabled in multi-select mode.");
                return;
            }
            if ((rType == "delete") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Delete",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to delete this series and all episodes?",
                    confirm: function () {
                        api(rID, rType, true);
                    }
                }).open();
			} else {
                rConfirm = true;
            }
            if (rConfirm) {
                $.getJSON("./api?action=series&sub=" + rType + "&series_id=" + rID, function(data) {
                    if (data.result == true) {
                        if (rType == "delete") {
                            $.toast("Series successfully deleted.");
                        }
                        $("#datatable-streampage").DataTable().ajax.reload( null, false );
                    } else {
                        $.toast("An error occured while processing your request.");
                    }
                }).fail(function() {
                    $.toast("An error occured while processing your request.");
                });
            }
		}
        function multiAPI(rType, rConfirm=false) {
            if (rType == "clear") {
                if ("#header_stats") {
                    $("#header_stats").show();
                }
                window.rSelected = [];
                $(".multiselect").hide();
                $("#datatable-streampage tr").removeClass(\'selectedfilter\').removeClass(\'ui-selected\').removeClass("selected");
                return;
            }
            if ((rType == "delete") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Delete",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to delete these streams?",
                    confirm: function () {
                        multiAPI(rType, true);
                    }
                }).open();
			} else {
                rConfirm = true;
            }
            if (rConfirm) {
                $.getJSON("./api?action=multi&type=series&sub=" + rType + "&ids=" + JSON.stringify(window.rSelected), function(data) {
                    if (data.result == true) {
                        if (rType == "delete") {
                            $.toast("Streams have been deleted.");
                            refreshTable();
                        }
                    } else {
                        $.toast("An error occured while processing your request.");
                    }
                }).fail(function() {
                    $.toast("An error occured while processing your request.");
                });
                multiAPI("clear");
            }
		}
