        function multiAPI(rType, rConfirm=false) {
            if (rType == "clear") {
                if ("#header_stats") {
                    $("#header_stats").show();
                }
                window.rSelected = [];
                $(".multiselect").hide();
                $("#datatable-streampage tr").removeClass(\'selectedfilter\').removeClass(\'ui-selected\').removeClass("selected");
                return;
            }
            if ((rType == "delete") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Delete",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to delete these episodes?",
                    confirm: function () {
                        multiAPI(rType, true);
                    }
                }).open();
            } else if ((rType == "purge") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Kill",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to kill all connections?",
                    confirm: function () {
                        multiAPI(rType, true);
                    }
                }).open();
			} else {
                rConfirm = true;
            }
            if (rConfirm) {
                $.getJSON("./api?action=multi&type=episode&sub=" + rType + "&ids=" + JSON.stringify(window.rSelected), function(data) {
                    if (data.result == true) {
                        if (rType == "start") {
                            $.toast("Episodes have started endoding.");
                        } else if (rType == "stop") {
                            $.toast("Episodes have stopped encoding.");
                        } else if (rType == "restart") {
                            $.toast("Episodes have been queued for re-encoding.");
                        } else if (rType == "delete") {
                            $.toast("Episodes have been deleted.");
                            refreshTable();
                        } else if (rType == "purge") {
                            $.toast("Connections have been killed.");
                        }
                    } else {
                        $.toast("An error occured while processing your request.");
                    }
                }).fail(function() {
                    $.toast("An error occured while processing your request.");
                });
                multiAPI("clear");
            }
		}
