        function multiAPI(rType, rConfirm=false) {
            if (rType == "clear") {
                if ("#header_stats") {
                    $("#header_stats").show();
                }
                window.rSelected = [];
                $(".multiselect").hide();
                $("#datatable-users tr").removeClass(\'selectedfilter\').removeClass(\'ui-selected\').removeClass("selected");
                return;
            }
            if ((rType == "delete") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Delete",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to delete these devices?",
                    confirm: function () {
                        multiAPI(rType, true);
                    }
                }).open();
            } else if ((rType == "purge") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Kill",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to kill all connections?",
                    confirm: function () {
                        multiAPI(rType, true);
                    }
                }).open();
            } else if ((rType == "convert") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Convert",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to convert these devices to normal lines?",
                    confirm: function () {
                        multiAPI(rType, true);
                    }
                }).open();
			} else {
                rConfirm = true;
            }
            if (rConfirm) {
                $.getJSON("./api?action=multi&type=enigma&sub=" + rType + "&ids=" + JSON.stringify(window.rSelected), function(data) {
                    if (data.result == true) {
                        if (rType == "convert") {
                            $.toast("Devices have been converted to normal lines.");
                        } else if (rType == "purge") {
                            $.toast("Connections have been killed.");
                        } else if (rType == "delete") {
                            $.toast("Devices have been deleted.");
                            refreshTable();
                        } else if (rType == "ban") {
                            $.toast("Devices have been banned.");
                        } else if (rType == "unban") {
                            $.toast("Devices have been unbanned.");
                        } else if (rType == "enable") {
                            $.toast("Devices have been enabled.");
                        } else if (rType == "disable") {
                            $.toast("Devices have been disabled.");
                        }
                        $("#datatable-users").DataTable().ajax.reload(null, false);
                    } else {
                        $.toast("An error occured while processing your request.");
                    }
                }).fail(function() {
                    $.toast("An error occured while processing your request.");
                });
                multiAPI("clear");
            }
		}
