                if (value.parent != "#") {
                    $("#on_demand").append(new Option(value.text, value.id));
                }
            });
            $("#on_demand").val(rOVal).trigger("change");
            if (!$("#on_demand").val()) {
                $("#on_demand").val(0).trigger("change");
            }
