		function moveDown(elem) {
			if ($(elem).parent().parent().parent().prevAll().length < $(".streams>tr").length) {
				$(elem).parent().parent().parent().insertAfter($(\'.streams>tr\').eq($(elem).parent().parent().parent().prevAll().length+1));
			}
		}
