		function selectEPGID() {
			$("#epg_lang").empty();
			if (rEPG[$("#epg_id").val()][$("#channel_id").val()]) {
				$.each(rEPG[$("#epg_id").val()][$("#channel_id").val()]["langs"], function(i, data) {
					$("#epg_lang").append(new Option(data, data, false, false));
