        function selectEPGAPI(rCallSign, rID, rTitle, rIcon) {
            $("#epg_api_id").val(rCallSign).trigger(\'change\');
            $("#epg_api_name").val(rTitle).trigger(\'change\');
            if ($("#stream_display_name").val().length == 0) {
                $("#stream_display_name").val(rTitle);
            }
            $.getJSON("./api?action=epg_api_single&id=" + rID, function(data) {
                $("#table-epg-data tbody").html("");
                if (data["data"].length == 0) {
                    data["data"].push({"startTime": "--", "program": {"title": "Uh oh!", "shortDescription": "No guide data is available at the moment."}})
                }
                $(data["data"]).each(function(rInt, rProgramme) {
                    $("#table-epg-data tbody").append(\'<tr><td class="text-center">\' + rProgramme["startTime"] + \'</td><td>\' + rProgramme["program"]["title"] + \'</td><td>\' + rProgramme["program"]["shortDescription"] + \'</td></tr>\');
                    $("#table-epg-data").show();
                });
                $(".bs-xuiepg-modal-center").modal("hide");
                if (rIcon) {
                    $("#epg-picon").attr("src", rIcon);
                    $(".bs-picon-modal-center").modal("show");
                }
            });
        }
        function evaluateServers() {
            var rVVal = $("#vframes_server_id").val();
            var rTVal = $("#tv_archive_server_id").val();
            var rOVal = $("#on_demand").val();
            $("#on_demand").empty();
            $("#vframes_server_id").empty().append(new Option("Disabled", 0));
            $("#tv_archive_server_id").empty().append(new Option("Disabled", 0));
            $($(\'#server_tree\').jstree(true).get_json(\'source\', {flat:true})).each(function(index, value) {
                if (value.parent != "#") {
                    $("#vframes_server_id").append(new Option(value.text, value.id));
                    $("#tv_archive_server_id").append(new Option(value.text, value.id));
                    $("#on_demand").append(new Option(value.text, value.id));
                }
            });
            $("#vframes_server_id").val(rVVal).trigger("change");
            if (!$("#vframes_server_id").val()) {
                $("#vframes_server_id").val(0).trigger("change");
            }
            $("#tv_archive_server_id").val(rTVal).trigger("change");
            if (!$("#tv_archive_server_id").val()) {
                $("#tv_archive_server_id").val(0).trigger("change");
            }
            $("#on_demand").val(rOVal).trigger("change");
            if (!$("#on_demand").val()) {
                $("#on_demand").val(0).trigger("change");
            }
        }
        function evaluateDirectSource() {
            $(["llod", "fps_restart", "fps_threshold", "adaptive_link", "custom_sid", "read_native", "gen_timestamps", "stream_all", "allow_record", "rtmp_output", "delay_minutes", "custom_ffmpeg", "probesize_ondemand", "transcode_profile_id", "custom_map", "days_to_restart", "time_to_restart", "on_demand", "tv_archive_duration", "tv_archive_server_id", "vframes_server_id", "restart_on_edit"]).each(function(rID, rElement) {
                if ($(rElement)) {
                    if ($("#direct_source").is(":checked")) {
                        if (window.rSwitches[rElement]) {
                            setSwitch(window.rSwitches[rElement], false);
                            window.rSwitches[rElement].disable();
                        } else {
                            $("#" + rElement).prop("disabled", true);
                        }
                    } else {
                        if (window.rSwitches[rElement]) {
                            window.rSwitches[rElement].enable();
                        } else {
                            $("#" + rElement).prop("disabled", false);
                        }
                    }
                }
            });
            $(["direct_proxy"]).each(function(rID, rElement) {
                if ($(rElement)) {
                    if (!$("#direct_source").is(":checked")) {
                        if (window.rSwitches[rElement]) {
                            setSwitch(window.rSwitches[rElement], false);
                            window.rSwitches[rElement].disable();
                        } else {
                            $("#" + rElement).prop("disabled", true);
                        }
                    } else {
                        if (window.rSwitches[rElement]) {
                            window.rSwitches[rElement].enable();
                        } else {
                            $("#" + rElement).prop("disabled", false);
                        }
                    }
                }
            });
            $(["user_agent", "http_proxy", "cookie", "headers"]).each(function(rID, rElement) {
                if ($(rElement)) {
                    if (($("#direct_proxy").is(":checked")) || (!$("#direct_source").is(":checked"))) {
                        if (window.rSwitches[rElement]) {
                            window.rSwitches[rElement].enable();
                        } else {
                            $("#" + rElement).prop("disabled", false);
                        }
                    } else {
                        if (window.rSwitches[rElement]) {
                            setSwitch(window.rSwitches[rElement], false);
                            window.rSwitches[rElement].disable();
                        } else {
                            $("#" + rElement).prop("disabled", true);
                        }
                    }
                }
            });
        }
