		function api(rID, rType, rConfirm=false) {
            if ((rType == "delete") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Delete",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to delete this IP?",
                    confirm: function () {
                        api(rID, rType, true);
                    }
                }).open();
			} else {
                rConfirm = true;
            }
            if (rConfirm) {
                $.getJSON("./api?action=rtmp_ip&sub=" + rType + "&ip=" + rID, function(data) {
                    if (data.result === true) {
                        if (rType == "delete") {
                            if (rRow = findRowByID($("#datatable").DataTable(), 0, rID)) {
                                $("#datatable").DataTable().rows(rRow).remove().draw(false);
                            }
                            $.toast("IP successfully deleted.");
                        }
                    } else {
                        $.toast("An error occured while processing your request.");
                    }
                });
            }
		}

