                    }
                }).open();
			} else {
                rConfirm = true;
            }
            if (rConfirm) {
                $.getJSON("./api?action=isp&sub=" + rType + "&isp_id=" + rID, function(data) {
                    if (data.result === true) {
                        if (rType == "delete") {
                            if (rRow = findRowByID($("#datatable").DataTable(), 0, rID)) {
                                $("#datatable").DataTable().rows(rRow).remove().draw(false);
                            }
                            $.toast("ISP successfully deleted.");
                        }
                    } else {
                        $.toast("An error occured while processing your request.");
                    }
                });
            }
		}

