        function getStreamIDs() {
            var rStreamIDs = [];
            var rIndexes = [];
            $("#datatable-streampage").DataTable().rows().every(function (rowIdx, tableLoop, rowLoop) {
                rStreamIDs.push($($("#datatable-streampage").DataTable().row(rowIdx).data()[0]).text());
                rIndexes.push(rowIdx);
            });
            return [rStreamIDs, rIndexes];
        }
        function refreshInformation() {
            if (!window.rProcessing) {
                var rUpdateColumns = [4,5,6,7,9];
                var rStreamIDs = getStreamIDs();
                if (rStreamIDs[0].length > 0) {
                    $.getJSON("./table?" + $.param($("#datatable-streampage").DataTable().ajax.params()) + "&refresh=" + rStreamIDs[0].join(","), function(rTable) {
                        if (!window.rProcessing) {
                            $(rTable.data).each(function(rIndex, rItem) {
                                for (i in rUpdateColumns) {
                                    var rIndex = rStreamIDs[0].indexOf($(rItem[0]).text());
                                    if (rIndex >= 0) {
                                        if ($(\'#datatable-streampage\').DataTable().cell(rStreamIDs[1][rIndex], rUpdateColumns[i]).data() != rItem[rUpdateColumns[i]]) {
                                            $(\'#datatable-streampage\').DataTable().cell(rStreamIDs[1][rIndex], rUpdateColumns[i]).data(rItem[rUpdateColumns[i]]);
                                        }
                                    }
                                }
                            });
                            bindHref(); refreshTooltips(false);
                        }
                    });
                }
            }
            clearTimeout(window.rRefresh);
            window.rRefresh = setTimeout(refreshInformation, 5000);
        }
		function api(rID, rServerID, rType, rConfirm=false) {
            if ((window.rSelected) && (window.rSelected.length > 0)) {
                $.toast("Individual actions disabled in multi-select mode.");
                return;
            }
            if ((rType == "delete") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Delete",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to delete this stream?",
                    confirm: function () {
                        api(rID, rServerID, rType, true);
                    }
                }).open();
            } else if ((rType == "purge") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Kill",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to kill all connections?",
                    confirm: function () {
                        api(rID, rServerID, rType, true);
                    }
                }).open();
            } else if ((rServerID == "kill") && (!rConfirm)) {
                rConfirm = true;
                rServerID = -1;
                rType = "kill";
			} else {
                rConfirm = true;
            }
            if (rConfirm) {
                $.getJSON("./api?action=stream&sub=" + rType + "&stream_id=" + rID + "&server_id=" + rServerID, function(data) {
                    if (data.result == true) {
                        if (rType == "start") {
                            $.toast("Stream successfully started.");
                        } else if (rType == "stop") {
                            $.toast("Stream successfully stopped.");
                        } else if (rType == "restart") {
                            $.toast("Stream successfully restarted.");
                        } else if (rType == "delete") {
                            $.toast("Stream successfully deleted.");
                            refreshTable();
                        } else if (rType == "kill") {
                            $.toast("Connection has been killed.");
                        } else if (rType == "purge") {
                            $.toast("Connections have been killed.");
                        }
                        if ($(".bs-streams-modal-center").is(":visible")) {
                            $("#datatable-sources").DataTable().ajax.reload( null, false );
                        }
                        if ($(".bs-live-modal-center").is(":visible")) {
                            $("#datatable-live").DataTable().ajax.reload( null, false );
                        }
                    } else {
                        $.toast("An error occured while processing your request.");
                    }
                }).fail(function() {
                    $.toast("An error occured while processing your request.");
                });
            }
		}
        function multiAPI(rType, rConfirm=false) {
            if (rType == "clear") {
                if ("#header_stats") {
                    $("#header_stats").show();
                }
                window.rSelected = [];
                $(".multiselect").hide();
                $("#datatable-streampage tr").removeClass(\'selectedfilter\').removeClass(\'ui-selected\').removeClass("selected");
                return;
            }
            if ((rType == "delete") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Delete",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to delete these streams?",
                    confirm: function () {
                        multiAPI(rType, true);
                    }
                }).open();
            } else if ((rType == "purge") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Kill",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to kill all connections?",
                    confirm: function () {
                        multiAPI(rType, true);
                    }
                }).open();
			} else {
                rConfirm = true;
            }
            if (rConfirm) {
                $.getJSON("./api?action=multi&type=stream&sub=" + rType + "&ids=" + JSON.stringify(window.rSelected), function(data) {
                    if (data.result == true) {
                        if (rType == "start") {
                            $.toast("Streams have been started.");
                        } else if (rType == "stop") {
                            $.toast("Streams have been stopped.");
                        } else if (rType == "restart") {
                            $.toast("Streams have been restarted.");
                        } else if (rType == "delete") {
                            $.toast("Streams have been deleted.");
                            refreshTable();
                        } else if (rType == "purge") {
                            $.toast("Connections have been killed.");
                        }
                    } else {
                        $.toast("An error occured while processing your request.");
                    }
                }).fail(function() {
                    $.toast("An error occured while processing your request.");
                });
                multiAPI("clear");
            }
		}
