		function MoveUp() {
			var rSelected = $(\'#domain_name option:selected\');
			if (rSelected.length) {
				var rPrevious = rSelected.first().prev()[0];
				if ($(rPrevious).html() != \'\') {
					rSelected.first().prev().before(rSelected);
				}
			}
		}
		function MoveDown() {
			var rSelected = $(\'#domain_name option:selected\');
			if (rSelected.length) {
				rSelected.last().next().after(rSelected);
			}
		}
