		function api(rID, rType, rConfirm=false) {
            if ((window.rSelected) && (window.rSelected.length > 0)) {
                $.toast("Individual actions disabled in multi-select mode.");
                return;
            }
            if ((rType == "delete") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Delete",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to delete this line?",
                    confirm: function () {
                        api(rID, rType, true);
                    }
                }).open();
            } else if ((rType == "kill") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Kill",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to kill all connections for this line?",
                    confirm: function () {
                        api(rID, rType, true);
                    }
                }).open();
			} else {
                rConfirm = true;
            }
            if (rConfirm) {
                $.getJSON("./api?action=line&sub=" + rType + "&user_id=" + rID, function(data) {
                    if (data.result === true) {
                        if (rType == "delete") {
                            $.toast("Line has been deleted.");
                        } else if (rType == "enable") {
                            $.toast("Line has been enabled.");
                        } else if (rType == "disable") {
                            $.toast("Line has been disabled.");
                        } else if (rType == "unban") {
                            $.toast("Line has been unbanned.");
                        } else if (rType == "ban") {
                            $.toast("Line has been banned.");
                        } else if (rType == "kill") {
                            $.toast("All connections for this line have been killed.");
                        }
                        $("#datatable-users").DataTable().ajax.reload(null, false);
                    } else {
                        $.toast("An error occured while processing your request.");
                    }
                });
            }
		}
        function multiAPI(rType, rConfirm=false) {
            if (rType == "clear") {
                if ("#header_stats") {
                    $("#header_stats").show();
                }
                window.rSelected = [];
                $(".multiselect").hide();
                $("#datatable-users tr").removeClass(\'selectedfilter\').removeClass(\'ui-selected\').removeClass("selected");
                return;
            }
            if ((rType == "delete") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Delete",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to delete these lines?",
                    confirm: function () {
                        multiAPI(rType, true);
                    }
                }).open();
            } else if ((rType == "purge") && (!rConfirm)) {
                new jBox("Confirm", {
                    confirmButton: "Kill",
                    cancelButton: "Cancel",
                    content: "Are you sure you want to kill all connections?",
                    confirm: function () {
                        multiAPI(rType, true);
                    }
                }).open();
			} else {
                rConfirm = true;
            }
            if (rConfirm) {
                $.getJSON("./api?action=multi&type=line&sub=" + rType + "&ids=" + JSON.stringify(window.rSelected), function(data) {
                    if (data.result == true) {
                        if (rType == "ban") {
                            $.toast("Lines have been banned.");
                        } else if (rType == "unban") {
                            $.toast("Lines have been unbanned.");
                        } else if (rType == "enable") {
                            $.toast("Lines have been enabled.");
                        } else if (rType == "disable") {
                            $.toast("Lines have been disabled.");
                        } else if (rType == "delete") {
                            $.toast("Lines have been deleted.");
                            refreshTable();
                        } else if (rType == "purge") {
                            $.toast("Connections have been killed.");
                        }
                        $("#datatable-users").DataTable().ajax.reload(null, false);
                    } else {
                        $.toast("An error occured while processing your request.");
                    }
                }).fail(function() {
                    $.toast("An error occured while processing your request.");
                });
                multiAPI("clear");
            }
		}
