                    $.getJSON("./table?" + $.param($("#datatable-activity").DataTable().ajax.params()) + "&refresh=" + rRowIDs[0].join(","), function(rTable) {
                        if (!window.rProcessing) {
                            var rActive = [];
                            $(rTable.data).each(function(rIndex, rItem) {
                                var rIndex = rRowIDs[0].indexOf(rItem[0]);
                                if (rIndex >= 0) {
                                    if ($(\'#datatable-activity\').DataTable().row(rRowIDs[1][rIndex]).data() != rItem) {
                                        $(\'#datatable-activity\').DataTable().row(rRowIDs[1][rIndex]).data(rItem);
                                    }
                                }
                                rActive.push(rIndex);
                            });
                            $(rRowIDs[1]).each(function(rIndex) {
                                if (rActive.indexOf(rIndex) == -1) {
                                    $(\'#datatable-activity\').DataTable().cell(rIndex, 8).data("<button type=\'button\' class=\'btn btn-secondary btn-xs waves-effect waves-light btn-fixed\'>CLOSED</button>");
                                }
                            });
                            bindHref(); refreshTooltips(false);
                        }
                    });
                }
            }
            clearTimeout(window.rRefresh);
            window.rRefresh = setTimeout(refreshInformation, 5000);
        }
